def first_element(t):
    """Return the first element of tuple t."""
    return t[0]


def last_element(t):
    """Return the last element of tuple t."""
    return t[-1]


def middle_elements(t):
    """Return a tuple of all elements except the first and last."""
    return t[1:-1]


def reverse_tuple(t):
    """Return a new tuple with elements in reverse order."""
    return t[::-1]
